import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Switch,
  Typography,
  Alert,
  Snackbar,
  Stack,
  CircularProgress,
  LinearProgress,
  useTheme
} from '@mui/material';
import { motion } from 'framer-motion';
import { getSettings, updateSettings } from '../services/api';

const Settings = () => {
  const theme = useTheme();
  const [settings, setSettings] = useState({
    listenAddr: '',
    listenPort: '',
    enableIPv6: false,
    upstreamDNS: '',
    cacheTTL: '',
    enableDNSSEC: false,
    enableLogging: false,
    enableMetrics: false,
    enableCache: false
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const data = await getSettings();
      setSettings(data);
    } catch (err) {
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field, value) => {
    setSettings(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      await updateSettings(settings);
      setSuccess(true);
    } catch (err) {
      setError('Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  const cardStyle = {
    height: '100%',
    transition: 'all 0.2s ease-in-out',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(26,35,126,0.7), rgba(49,27,146,0.7))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.1)'
      : '1px solid rgba(255,255,255,0.5)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 6px 16px 0 rgba(0,0,0,0.4), 0 3px 6px -2px rgba(0,0,0,0.5)'
        : '0 6px 16px 0 rgba(31,38,135,0.25), 0 3px 6px -2px rgba(31,38,135,0.3)',
    }
  };

  const headerCardStyle = {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.3), 0 2px 4px -1px rgba(0,0,0,0.4)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: '1px solid rgba(255,255,255,0.1)',
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={headerCardStyle}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" spacing={2}>
            <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
              系统设置
            </Typography>
            {loading && (
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
              </Box>
            )}
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <motion.div
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <Grid container spacing={1.5}>
          <Grid item xs={12} md={6}>
            <motion.div variants={cardVariants}>
              <Card sx={cardStyle}>
